module top_module(
  input in,
  input [n-1:0] ctrl,
  output [2**n-1:0] out
);parameter n = 3; // number of control signals

assign out[0] = ctrl == 0 ? in : 0;
assign out[1] = ctrl == 1 ? in : 0;
assign out[2] = ctrl == 2 ? in : 0;
assign out[3] = ctrl == 3 ? in : 0;
assign out[4] = ctrl == 4 ? in : 0;
assign out[5] = ctrl == 5 ? in : 0;
assign out[6] = ctrl == 6 ? in : 0;
assign out[7] = ctrl == 7 ? in : 0;

endmodule
